import React, { useState, useEffect } from 'react';
import axios from 'axios';
import AdminDashboard from './AdminDashboard';
import { Wallet, LogOut, Send, User, Lock } from 'lucide-react';

const API_BASE = "https://cna-finance-api.onrender.com/api";

function App() {
  const [user, setUser] = useState(null);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [amount, setAmount] = useState('');
  const [loading, setLoading] = useState(false);

  // --- ALTERAÇÃO DE OURO: PERSISTÊNCIA ---
  useEffect(() => {
    const savedUser = localStorage.getItem('cna_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
  }, []);

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await axios.post(`${API_BASE}/login`, { username, password });
      setUser(res.data);
      localStorage.setItem('cna_user', JSON.stringify(res.data));
    } catch (err) {
      alert("Erro ao logar. Verifique usuário e senha.");
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('cna_user');
    setUser(null);
  };

  // --- ALTERAÇÃO DE OURO: PAGAMENTO SEM LOGOUT ---
  const handlePayment = async () => {
    const value = parseFloat(amount);
    if (!value || value <= 0) return alert("Digite um valor válido.");
    if (user.balance < value) return alert("Saldo insuficiente.");

    try {
      const res = await axios.post(`${API_BASE}/user/pay`, {
        user_id: user.id,
        value: value
      });

      if (res.status === 200) {
        // Atualiza apenas o saldo mantendo o resto do usuário
        const updatedUser = { ...user, balance: res.data.new_balance };
        setUser(updatedUser);
        localStorage.setItem('cna_user', JSON.stringify(updatedUser));

        alert(`CNA$ ${value} pagos com sucesso!`);
        setAmount('');
      }
    } catch (err) {
      alert(err.response?.data?.error || "Erro na transação.");
    }
  };

  if (!user) {
    return (
      <div style={styles.loginContainer}>
        <div style={styles.loginBox}>
          <h2 style={{ textAlign: 'center', color: 'white' }}>CNA Finance</h2>
          <form onSubmit={handleLogin} style={styles.form}>
            <div style={styles.inputGroup}>
              <User size={18} color="#94a3b8" />
              <input 
                type="text" placeholder="Usuário" 
                value={username} onChange={(e) => setUsername(e.target.value)} 
                style={styles.input} required
              />
            </div>
            <div style={styles.inputGroup}>
              <Lock size={18} color="#94a3b8" />
              <input 
                type="password" placeholder="Senha" 
                value={password} onChange={(e) => setPassword(e.target.value)} 
                style={styles.input} required
              />
            </div>
            <button type="submit" style={styles.loginBtn} disabled={loading}>
              {loading ? 'Entrando...' : 'Entrar'}
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.appContainer}>
      <nav style={styles.nav}>
        <span style={styles.userName}>Olá, <b>{user.username}</b></span>
        <button onClick={handleLogout} style={styles.logoutBtn}>
          <LogOut size={16} /> Sair
        </button>
      </nav>

      <main style={styles.main}>
        {/* CARD DE SALDO */}
        <div style={styles.balanceCard}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <Wallet color="#10b981" size={24} />
            <span style={styles.balanceLabel}>Saldo Disponível</span>
          </div>
          <h1 style={styles.balanceValue}>CNA$ {user.balance.toFixed(2)}</h1>
        </div>

        {/* ÁREA DE PAGAMENTO (Só para usuários comuns) */}
        {user.role !== 'admin' && (
          <div style={styles.paySection}>
            <h3 style={{ color: 'white', fontSize: '16px' }}>Realizar Pagamento</h3>
            <div style={styles.payInputGroup}>
              <input 
                type="number" placeholder="0.00" 
                value={amount} onChange={(e) => setAmount(e.target.value)} 
                style={styles.payInput}
              />
              <button onClick={handlePayment} style={styles.payBtn}>
                <Send size={18} /> Confirmar
              </button>
            </div>
          </div>
        )}

        {/* PAINEL ADMIN (Só para administradores) */}
        {user.role === 'admin' && <AdminDashboard />}
      </main>
    </div>
  );
}

const styles = {
  loginContainer: { height: '100vh', display: 'flex', justifyContent: 'center', alignItems: 'center', backgroundColor: '#0f172a' },
  loginBox: { backgroundColor: '#1e293b', padding: '40px', borderRadius: '20px', width: '320px', border: '1px solid #334155' },
  form: { display: 'flex', flexDirection: 'column', gap: '15px', marginTop: '20px' },
  inputGroup: { display: 'flex', alignItems: 'center', gap: '10px', backgroundColor: '#0f172a', padding: '12px', borderRadius: '10px', border: '1px solid #334155' },
  input: { background: 'none', border: 'none', color: 'white', outline: 'none', width: '100%' },
  loginBtn: { backgroundColor: '#E50136', color: 'white', border: 'none', padding: '12px', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer' },
  appContainer: { minHeight: '100vh', backgroundColor: '#0f172a', color: 'white', padding: '20px' },
  nav: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' },
  userName: { fontSize: '14px', color: '#94a3b8' },
  logoutBtn: { display: 'flex', alignItems: 'center', gap: '5px', background: 'none', border: 'none', color: '#64748b', cursor: 'pointer' },
  main: { maxWidth: '600px', margin: '0 auto' },
  balanceCard: { backgroundColor: '#1e293b', padding: '25px', borderRadius: '24px', border: '1px solid #334155', marginBottom: '20px' },
  balanceLabel: { color: '#94a3b8', fontSize: '14px' },
  balanceValue: { fontSize: '36px', margin: '10px 0 0 0', color: '#10b981' },
  paySection: { backgroundColor: '#1e293b', padding: '20px', borderRadius: '20px', border: '1px solid #334155' },
  payInputGroup: { display: 'flex', gap: '10px', marginTop: '15px' },
  payInput: { flex: 1, backgroundColor: '#0f172a', border: '1px solid #334155', borderRadius: '10px', padding: '12px', color: 'white', outline: 'none' },
  payBtn: { backgroundColor: '#10b981', border: 'none', borderRadius: '10px', padding: '0 20px', color: 'white', fontWeight: 'bold', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' }
};

export default App;
